$script = @'
const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');
(async () => {
  const outDir = process.argv[2];
  fs.mkdirSync(outDir, { recursive: true });
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1280, height: 720 } });
  const result = { startedAt: new Date().toISOString(), steps: [] };
  await page.goto('https://example.com', { waitUntil: 'domcontentloaded', timeout: 60000 });
  result.steps.push({ name: 'navigate', ok: true, url: page.url() });
  result.title = await page.title();
  result.h1 = await page.locator('h1').textContent();
  result.paragraph = await page.locator('p').first().textContent();
  result.steps.push({ name: 'extract_text', ok: true, title: result.title, h1: result.h1 });
  const screenshot = path.join(outDir, 'example-com.png');
  await page.screenshot({ path: screenshot, fullPage: true });
  result.steps.push({ name: 'screenshot', ok: true, path: screenshot });
  const requests = [];
  page.on('request', r => requests.push(r.url()));
  await page.goto('https://www.iana.org/domains/reserved', { waitUntil: 'domcontentloaded', timeout: 60000 });
  result.steps.push({ name: 'second_navigation', ok: true, url: page.url() });
  result.secondTitle = await page.title();
  result.linkCount = await page.locator('a').count();
  result.steps.push({ name: 'inspect_links', ok: result.linkCount > 0, linkCount: result.linkCount });
  result.finishedAt = new Date().toISOString();
  fs.writeFileSync(path.join(outDir, 'baseline-result.json'), JSON.stringify(result, null, 2));
  await browser.close();
})().catch(err => {
  console.error(err);
  process.exit(1);
});
